import { put, call } from '@redux-saga/core/effects';
import { api } from '@semparar/mf-app-user';
import { eventServerResponse } from '~/constants/functions';

import {
  PointsActions,
  PointsExtractData,
  ProcessedExtractData,
} from '../../ducks/points';
import { processPointsExtractData } from './processExtractData';

interface PointsExtractResponse {
  data: {
    data: {
      transactions: Array<{
        id: string;
        date: string;
        description: string;
        type: 'RECEIVED' | 'DEBIT' | 'EXPIRED' | 'REFUNDED';
        amount: number;
        currencyValue: number;
        icon: string;
        details: {
          provider: string;
          extraInfo: string;
          fields: Array<{
            label: string;
            value: string;
          }>;
        };
      }>;
      expiringPoints: Array<{
        amount: number;
        expirationDate: string;
      }>;
      transactionsFilters: {
        periods: Array<{
          value: number;
          label: string;
        }>;
        types: Array<{
          value: string;
          label: string;
        }>;
      };
      expiringFilters: {
        periods: Array<{
          value: number;
          label: string;
        }>;
      };
    };
    status: {
      httpStatus: number;
      returnCode: number;
      message: string;
    };
  };
}

export const TYPE_LABELS: Record<string, string> = {
  RECEIVED: 'Ganhos',
  DEBIT: 'Usados',
  EXPIRED: 'Expirados',
  REFUNDED: 'Estornados',
};

export function* getPointsExtract() {
  try {
    const response: PointsExtractResponse = yield call(
      api.get,
      'fintech/v1/rewardProgram/statement',
      {},
    );

    const returnCode = response?.data?.status?.returnCode;

    if (returnCode === 200) {
      const types = response.data.data.transactionsFilters.types.map(type => ({
        value: type.value,
        label: TYPE_LABELS[type.value] || type.label,
      }));

      const extractData: PointsExtractData = {
        transactions: response.data.data.transactions,
        expiringPoints: response.data.data.expiringPoints,
        transactionsFilters: {
          periods: response.data.data.transactionsFilters.periods,
          types,
        },
        expiringFilters: {
          periods: response.data.data.expiringFilters.periods,
        },
      };

      const processedData: ProcessedExtractData =
        processPointsExtractData(extractData);

      yield put(PointsActions.successPointsExtract(extractData, processedData));

      eventServerResponse({
        content_type: 'sucesso',
        content_id: 'rewardprogram/v1/statement',
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'extrato_hub_recompensas',
      });
    } else {
      yield put(PointsActions.failedPointsExtract());
      eventServerResponse({
        content_type: 'erro',
        content_id: 'rewardprogram/v1/statement',
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'extrato_hub_recompensas',
      });
    }
  } catch (error) {
    yield put(PointsActions.failedPointsExtract());
    eventServerResponse({
      content_type: 'erro',
      content_id: 'rewardprogram/v1/statement',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'extrato_hub_recompensas',
    });
  }
}

