import { getPointsProductsApi } from '../api';
import {
  mapProductsResponse,
  extractConversionFactor,
  extractInvoiceConversionFactor,
  isSuccessResponse,
} from '../repository';
import { useRootStore } from '~/store';
import { PointsProductsStatus } from '../models';
import { eventServerResponse } from '~/constants/functions';
import { PRODUCTS_CONSTANTS, ANALYTICS_EVENTS } from '../constants';

function shouldFetchProducts(status: PointsProductsStatus): boolean {
  return (
    status !== PointsProductsStatus.LOADING &&
    status !== PointsProductsStatus.SUCCESS
  );
}

function handleProductsSuccess(
  products: ReturnType<typeof mapProductsResponse>,
): void {
  const { pointsProductsActions } = useRootStore.getState();

  pointsProductsActions.setProducts(products);

  const conversionFactor = extractConversionFactor(products);
  if (conversionFactor > 0) {
    pointsProductsActions.setConversionFactor(conversionFactor);
  }

  const invoiceConversionFactor = extractInvoiceConversionFactor(products);
  if (invoiceConversionFactor) {
    pointsProductsActions.setConversionFactor(invoiceConversionFactor);
  }

  eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_SUCCESS);
}

function handleProductsError(): void {
  const { pointsProductsActions } = useRootStore.getState();
  pointsProductsActions.setError('Failed to load products');
  eventServerResponse(ANALYTICS_EVENTS.PRODUCTS_ERROR);
}

export async function getPointsProducts(): Promise<void> {
  const { pointsProductsActions, pointsProducts } = useRootStore.getState();

  if (!shouldFetchProducts(pointsProducts.status)) {
    return;
  }

  try {
    pointsProductsActions.setStatus(PointsProductsStatus.LOADING);

    const response = await getPointsProductsApi();

    if (isSuccessResponse(response)) {
      const products = mapProductsResponse(response);
      handleProductsSuccess(products);
      return;
    }

    handleProductsError();
  } catch {
    handleProductsError();
  }
}

export function resetProducts(): void {
  const { pointsProductsActions } = useRootStore.getState();
  pointsProductsActions.reset();
}

